theme.custom_css_code:
.lotto-widget{
  --bg:#1c1d20;
  --card:#25272c;
  --card-2:#2d3036;
  --line:rgba(255,255,255,0.10);
  --text:#f3f4f6;
  --muted:#a9afbb;
  --accent:#f4c542;
  --accent-2:#7dd3fc;
  --accent-3:#86efac;
  --accent-4:#fda4af;
  width:100%;
  background:transparent;
  font-family:Arial,Helvetica,sans-serif;
  color:var(--text);
  box-sizing:border-box;
}
.lotto-card{
  background:var(--bg);
  border:1px solid var(--line);
  border-radius:20px;
  padding:24px;
  box-sizing:border-box;
  box-shadow:0 10px 30px rgba(0,0,0,0.22);
}
.lotto-table-wrap{
  width:100%;
  overflow-x:auto;
}
.lotto-table{
  width:100%;
  min-width:640px;
  border-collapse:collapse;
}
.lotto-table td{
  padding:14px 16px;
  border-bottom:1px solid var(--line);
  font-size:15px;
  line-height:1.45;
  vertical-align:top;
}
.lotto-table tr:last-child td{
  border-bottom:none;
}
.lotto-table td:first-child{
  width:38%;
  color:var(--muted);
}
.lotto-table td:last-child{
  color:var(--text);
  font-weight:600;
}
.lotto-note{
  margin-top:16px;
  color:var(--muted);
  font-size:13px;
  line-height:1.5;
}
.lotto-section{
  display:grid;
  gap:18px;
}
.lotto-chart-title{
  font-size:20px;
  line-height:1.2;
  font-weight:700;
  margin:0;
}
.lotto-chart-sub{
  margin:0;
  color:var(--muted);
  font-size:14px;
  line-height:1.5;
}
.lotto-bars{
  display:grid;
  gap:14px;
  margin-top:6px;
}
.lotto-bar-row{
  display:grid;
  grid-template-columns:160px 1fr 58px;
  gap:14px;
  align-items:center;
}
.lotto-bar-label{
  color:var(--text);
  font-size:14px;
  line-height:1.35;
}
.lotto-bar-track{
  width:100%;
  height:14px;
  background:var(--card-2);
  border-radius:999px;
  overflow:hidden;
  position:relative;
}
.lotto-bar-fill{
  height:100%;
  border-radius:999px;
  background:linear-gradient(90deg,var(--accent),var(--accent-2));
}
.lotto-bar-fill.alt{
  background:linear-gradient(90deg,var(--accent-3),var(--accent-2));
}
.lotto-bar-fill.soft{
  background:linear-gradient(90deg,var(--accent-4),var(--accent));
}
.lotto-bar-val{
  text-align:right;
  color:var(--muted);
  font-size:13px;
  font-weight:700;
}
.lotto-legend{
  display:flex;
  flex-wrap:wrap;
  gap:10px 18px;
  margin-top:6px;
}
.lotto-legend-item{
  display:flex;
  align-items:center;
  gap:8px;
  color:var(--muted);
  font-size:13px;
}
.lotto-dot{
  width:10px;
  height:10px;
  border-radius:50%;
  display:inline-block;
}
.lotto-dot.a{background:var(--accent);}
.lotto-dot.b{background:var(--accent-2);}
.lotto-dot.c{background:var(--accent-3);}
.lotto-grid{
  display:grid;
  grid-template-columns:1fr 1fr;
  gap:18px;
}
.lotto-compare{
  display:grid;
  gap:16px;
  margin-top:6px;
}
.lotto-compare-row{
  display:grid;
  gap:8px;
}
.lotto-compare-head{
  display:flex;
  justify-content:space-between;
  gap:12px;
  align-items:center;
  font-size:14px;
  line-height:1.35;
}
.lotto-compare-label{
  color:var(--text);
  font-weight:600;
}
.lotto-compare-bars{
  display:grid;
  gap:8px;
}
.lotto-mini{
  display:grid;
  grid-template-columns:92px 1fr 46px;
  gap:12px;
  align-items:center;
}
.lotto-mini-name{
  color:var(--muted);
  font-size:12px;
}
.lotto-mini-track{
  height:10px;
  background:var(--card-2);
  border-radius:999px;
  overflow:hidden;
}
.lotto-mini-fill{
  height:100%;
  border-radius:999px;
}
.lotto-mini-fill.brand{
  background:linear-gradient(90deg,var(--accent),var(--accent-2));
}
.lotto-mini-fill.market{
  background:rgba(255,255,255,0.24);
}
.lotto-mini-val{
  color:var(--muted);
  font-size:12px;
  text-align:right;
  font-weight:700;
}
@media (max-width:860px){
  .lotto-grid{
    grid-template-columns:1fr;
  }
}
@media (max-width:640px){
  .lotto-card{
    padding:18px;
    border-radius:16px;
  }
  .lotto-bar-row{
    grid-template-columns:1fr;
    gap:8px;
  }
  .lotto-bar-val{
    text-align:left;
  }
  .lotto-mini{
    grid-template-columns:78px 1fr 40px;
    gap:10px;
  }
  .lotto-chart-title{
    font-size:18px;
  }
}
